def _get_decorators(node, src_bytes: bytes) -> list[str]:
    decorators = []
    for child in node.children:
        if child.type == "decorator":
            raw = src_bytes[child.start_byte:child.end_byte].decode("utf-8", errors="ignore")
            decorators.append(raw.strip())
    return decorators
